import PropertyCard from "./Components/PropertyCard";   
import ListingNav from "./navbar/listing-nav";
import properties from "./data/properties";

function Listings() {

    const [priceFilter, setPriceFilter] = useState("all");

    const filteredProperties = properties.filter((property) => {
        if (priceFilter === "low") return property.price < 3000;
        if (priceFilter === "mid") return property.price >= 3000 && property.price <= 4500;
        if (priceFilter === "high") return property.price > 4500;
        return true;
    });
    
    return (
        <div>
            <section className="hero-v2">
                <h1>Seek your Perfect Home</h1>
            </section>

            <section className="featured">
                <h2>Properties</h2>
                <div className="filter-container">
                    <ListingNav/>
                </div>
                <div className="listing-properties">
                    {properties.map((property)=>( <PropertyCard key={property.id} property={property} large/>))}
                </div>
            </section>
           </div>
    );
}

export default Listings;
